+        )
+        .unwrap();
+        insert(
+            &cx,
+            &dev,
+            &mut root,
+            Ext4Extent {
+                logical_block: 20,
+                raw_len: 2,
+                physical_start: 600,
+            },
+            &mut alloc,
+        )
+        .unwrap();
+
+        // Block 0 should be a hole with length 5 (until the first extent).
+        let result = search(&cx, &dev, &root, 0).unwrap();
